import base64
import os

# 16x16 minimal transparent valid ICO file base64
B64_ICO = ""

favicon_path = os.path.join("public", "favicon.ico")
if not os.path.exists("public"):
    os.makedirs("public")

try:
    from PIL import Image, ImageDraw, ImageFont
    # Generate a nice 32x32 rounded rectangle with 'CZ' text
    img = Image.new('RGBA', (32, 32), color=(0, 0, 0, 0))
    d = ImageDraw.Draw(img)
    # Background gradient approximation (purple to blue)
    d.rounded_rectangle([(0, 0), (32, 32)], radius=6, fill=(192, 132, 252, 255))
    
    # Try using default font, fallback to basic drawing if missing
    try:
        font = ImageFont.truetype("arial.ttf", 16)
    except:
        font = ImageFont.load_default()
        
    d.text((16, 16), "CZ", fill=(255,255,255,255), anchor="mm", font=font)
    img.save(favicon_path, format="ICO")
    print("Generated dynamic favicon via PIL.")
except ImportError:
    # Use base64 transparent fallback
    with open(favicon_path, "wb") as f:
        f.write(base64.b64decode(B64_ICO))
    print("Generated base64 fallback favicon.")
